function format_date(t){var e=t.getFullYear(),n=t.getMonth()+1,a=t.getDate(),u=t.getHours(),o=t.getMinutes(),r=t.getSeconds(),i=t.getMilliseconds();function g(t){return t<=9?"0"+t:t}return e+"-"+g(n)+"-"+g(a)+" "+g(u)+":"+g(o)+":"+g(r)+"."+g(i)}function datesEqual(t,e,n){QUnit.push(QUnit.equiv(t,e),format_date(t),format_date(e),n)}